sql:
SELECT DISTINCT a.first_name || ' ' || a.last_name AS Athlete_Name
FROM athletes a
JOIN results r ON a.athlete_id = r.athlete_id;

SELECT MAX(graduation_year) 
FROM athletes 
WHERE last_name LIKE '%a%';

SELECT a.first_name, a.last_name, t.team_name, t.university
FROM athletes a
INNER JOIN teams t ON a.team_id = t.team_id;

SELECT DISTINCT graduation_year 
FROM athletes
ORDER BY graduation_year;

SELECT first_name, last_name, height
FROM athletes
WHERE height > (SELECT AVG(height) FROM athletes);

SELECT ath.first_name || ' ' || ath.last_name AS Athlete_Name, t.team_name AS Team_Name
FROM athletes AS ath
INNER JOIN teams AS t ON ath.team_id = t.team_id;

SELECT first_name, last_name, graduation_year
FROM athletes
WHERE team_id = 100;
